  describe('notification ordering', () => {
    it('should deliver notifications in order even with async adapters', async () => {
      const deliveryOrder: string[] = [];

      // Adapter that introduces variable delays — without proper ordering,
      // faster notifications would arrive before slower ones.
      const slowAdapter: NotificationAdapter = {
        channel: 'email',
        async send(payload: NotificationPayload) {
          const delay = payload.subject.includes('Confirmation') ? 50 : 10;
          await new Promise((resolve) => setTimeout(resolve, delay));
          deliveryOrder.push(payload.subject);
          return { success: true };
        },
      };

      service.registerAdapter(slowAdapter);

      // Emit order created (slow: 50ms) then status changed (fast: 10ms).
      // Without ordering, the status change would arrive first.
      const orderCreatedEvent: OrderCreatedEvent = {
        type: 'order:created',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [{ productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 }],
          total: 10,
          status: 'pending',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        user: {
          id: 'user-1',
          name: 'Alice',
          email: 'alice@example.com',
          role: 'member',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        timestamp: new Date(),
      };

      const statusChangedEvent: OrderStatusChangedEvent = {
        type: 'order:status-changed',
        order: {
          id: 'order-1',
          userId: 'user-1',
          items: [],
          total: 10,
          status: 'confirmed',
          createdAt: new Date(),
          updatedAt: new Date(),
        },
        previousStatus: 'pending',
        newStatus: 'confirmed',
        timestamp: new Date(),
      };

      await eventBus.emit(orderCreatedEvent);
      await eventBus.emit(statusChangedEvent);

      expect(deliveryOrder).toHaveLength(2);
      expect(deliveryOrder[0]).toContain('Confirmation');
      expect(deliveryOrder[1]).toContain('Update');
    });
  });
});

